mapper.select:
SELECT TM_ID, SSNT_YR, MKT_SZ, PPLT_RTG, FAN_LYLTY, FAN_EXP,
       REG_INTRST, NATNL_PPLT, MRCH_PWR, AVG_ATND_CNT, SSNT_TCKT_HLDR
FROM TM_MKT_SSNT
WHERE TM_ID = #{tmId}
  AND SSNT_YR = #{ssntYr}

SELECT COUNT(*)
FROM TM_FCLTY_UPGR
WHERE TM_ID = #{tmId}
  AND FCLTY_TYPE_CD = #{fcltyTypeCd}
  AND UPGR_STTS_CD = 'PROG'

mapper.update:
UPDATE TM_FCLTY
   SET FCLTY_LVL = #{newLvl}
 WHERE TM_ID = #{tmId}
   AND FCLTY_TYPE_CD = #{fcltyTypeCd}

UPDATE TM_FNC_SSNT
   SET CUR_CASH       = CUR_CASH - #{upgrCost}
     , CUR_FCLTY_COST = COALESCE(CUR_FCLTY_COST, 0) + #{upgrCost}
 WHERE TM_ID    = #{tmId}
   AND SSNT_YR  = (SELECT MAX(SSNT_YR) FROM SSNT)
   AND CUR_CASH IS NOT NULL
   AND CUR_CASH >= #{upgrCost}

UPDATE STDM
   SET STDM_SEAT_CNT = #{seatCnt}
 WHERE STDM_ID = #{stdmId}
